  "Vinícius Júnior": { zh: "维尼修斯", rating: 8.4, tags: ["左路过人", "高速突破", "制造点球"] },
  "Vinicius Junior": { zh: "维尼修斯", rating: 8.4, tags: ["左路过人", "高速突破", "制造点球"] },
  "Kevin De Bruyne": { zh: "德布劳内", rating: 8.3, tags: ["大师级传球", "弧线传中", "远射"] },
