  "Mohamed Salah": { zh: "萨拉赫", rating: 8.6, tags: ["右路终结", "反击核心", "领袖"] },
  "Neymar": { zh: "内马尔", rating: 8.2, tags: ["创造力", "定位球", "盘带"] },
