async function main() {
  const [teamsRaw, matchesRaw, stadiaRaw] = await Promise.all([
    getJSON("football.teams.json"),
    pullMatchesRaw(),
    getJSON("football.stadiums.json"),
  ]);

  const teams = teamsRaw.map(toTeam);
  const teamById = new Map(teamsRaw.map((team, index) => [String(team.id), teams[index]]));
  const stadiumById = new Map(stadiaRaw.map((stadium) => [String(stadium.id), stadium]));
  const matches = matchesRaw
    .map((match) => toMatch(match, teamById, stadiumById))
    .sort((a, b) => Number(a.id.slice(1)) - Number(b.id.slice(1)));
  const players = await pullPlayers(teams);

  await writeFile(
    "lib/generated/worldcup-data.ts",
    `// ${SOURCE_NOTE}\nimport type { Match, Team } from "../worldcup";\n\nexport const GENERATED_TEAMS = ${literal(teams)} satisfies Team[];\n\nexport const GENERATED_MATCHES = ${literal(matches)} satisfies Match[];\n`,
  );

  await writeFile(
    "lib/generated/player-data.ts",
    `// ${SOURCE_NOTE}\nimport type { Player } from "../players";\n\nexport const GENERATED_PLAYERS = ${literal(players)} satisfies Player[];\n`,
  );

  console.log(`Generated ${teams.length} teams, ${matches.length} matches, ${players.length} players.`);
}

async function getJSON(file) {
  const res = await fetch(RAW + file);
  if (!res.ok) throw new Error(`${file}: HTTP ${res.status}`);
  return res.json();
}

async function pullMatchesRaw() {
  try {
    const res = await fetch(LIVE_GAMES, { headers: { "user-agent": "Mozilla/5.0" } });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    const games = Array.isArray(data) ? data : data.games;
    if (!Array.isArray(games) || games.length < 104) {
      throw new Error(`Expected 104 games, got ${games?.length ?? 0}`);
    }
    console.log(`Pulled ${games.length} live games from ${LIVE_GAMES}`);
    return games;
  } catch (error) {
    console.warn(`Live games unavailable (${error.message}); falling back to static GitHub schedule.`);
    return getJSON("football.matches.json");
  }
}

function toTeam(team) {
  const code = CODE_OVERRIDES[team.iso2] ?? String(team.iso2).toLowerCase();
  const [zh, fifaRank, elo, confederation] = TEAM_META[team.name_en] ?? [team.name_en, 80, 1580, "TBD"];
  return {
    code,
    name: team.name_en,
    zh,
    group: team.groups,
    fifaRank,
    elo,
    confederation,
  };
}

function toMatch(match, teamById, stadiumById) {
  const stadium = stadiumById.get(String(match.stadium_id));
  const home = teamById.get(String(match.home_team_id));
  const away = teamById.get(String(match.away_team_id));
  const status = matchStatus(match);
  const score = readScore(match, status);
  const out = {
    id: `m${match.id}`,
    stage: STAGE_BY_TYPE[match.type] ?? "Group",
    group: match.type === "group" ? match.group : undefined,
    home: home?.code,
    away: away?.code,
    homeLabel: home?.zh ?? match.home_team_label,
    awayLabel: away?.zh ?? match.away_team_label,
    kickoff: localToUtc(match.local_date, Number(match.stadium_id)),
    kickoffLocal: match.local_date,
    venue: stadium?.fifa_name ?? stadium?.name_en ?? "TBD",
    city: stadium?.city_en ?? "TBD",
    status,
  };
  if (score) out.score = score;
  return out;
}

function matchStatus(match) {
  const finished = String(match.finished).toUpperCase() === "TRUE";
  const elapsed = String(match.time_elapsed ?? "").toLowerCase();
  if (finished || elapsed === "finished") return "finished";
  if (elapsed && elapsed !== "notstarted" && elapsed !== "not started") return "live";
  return "scheduled";
}

function readScore(match, status) {
  if (status === "scheduled") return undefined;
  const home = Number(match.home_score);
  const away = Number(match.away_score);
  if (!Number.isFinite(home) || !Number.isFinite(away)) return undefined;
  return [home, away];
}

function localToUtc(local, stadiumId) {
  const match = String(local).match(/(\d{2})\/(\d{2})\/(\d{4})\s+(\d{2}):(\d{2})/);
  if (!match) return "2026-06-11T00:00:00.000Z";
  const [, mm, dd, yyyy, hh, min] = match.map(String);
  const offset = STADIUM_OFFSETS[stadiumId] ?? -4;
  return new Date(Date.UTC(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh) - offset, Number(min))).toISOString();
}

async function pullPlayers(teams) {
  const indexHTML = await fetchText(SQUADS);
  const cards = [...indexHTML.matchAll(/<a href="([^"]+)" class="squad-card__link" aria-label="([^"]+)"><\/a>/g)].map(
    ([, href, name]) => ({ href, name: decode(name) }),
  );
  const hrefByName = new Map(cards.map((card) => [card.name, card.href]));
  const players = [];

  for (const team of teams) {
    const href = hrefByName.get(team.name);
    if (!href) continue;
    try {
      const html = await fetchText(href);
      players.push(...parseSquadPage(html, team));
    } catch (error) {
      console.warn(`Skipping ${team.name}: ${error.message}`);
    }
  }

  return players.sort((a, b) => b.rating - a.rating || a.team.localeCompare(b.team) || a.name.localeCompare(b.name));
}

async function fetchText(url) {
  const res = await fetch(url, { headers: { "user-agent": "Mozilla/5.0" } });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.text();
}

function parseSquadPage(html, team) {
  const out = [];
  const sections = [...html.matchAll(/<section class="squad-section squad-section--(gk|df|mf|fw)">([\s\S]*?)<\/section>/g)];
  for (const [, section, body] of sections) {
    const position = POSITION_BY_SECTION[section];
    const rows = [...body.matchAll(/<tr>([\s\S]*?)<\/tr>/g)].slice(1);
    rows.forEach(([, row], index) => {
      const cells = [...row.matchAll(/<td(?: class="num")?>([\s\S]*?)<\/td>/g)].map((cell) => clean(cell[1]));
      if (cells.length < 3 || !cells[0]) return;
      const name = normalizePlayerName(cells[0]);
      const age = Number(cells[1]) || 26;
      const club = cells[2] || "Unattached";
      const goals = numberOrZero(cells[4]);
      const featured = FEATURED[name] ?? {};
      const rating = featured.rating ?? ratingFor(team, position, index, age, club);
      const number = position === "GK" ? index + 1 : index + 2;
      out.push({
        id: slug(`${team.code}-${name}`),
        name,
        zh: featured.zh ?? name,
        team: team.code,
        number,
        position,
        age,
        club,
        rating,
        styleTags: featured.tags ?? tagsFor(position),
        attrs: attrsFor(position, rating, age),
        stats: {
          apps: 0,
          goals,
          assists: 0,
          xg: Number((Math.max(0, goals) * 0.72).toFixed(1)),
        },
      });
    });
  }
  return out;
}

function ratingFor(team, position, index, age, club) {
  const base = 6.25 + Math.max(0, team.elo - 1500) / 360;
  const role = position === "GK" ? 0.05 : position === "DF" ? 0.02 : position === "MF" ? 0.12 : 0.18;
  const squadOrder = Math.max(0, 0.7 - index * 0.045);
  const ageCurve = Math.max(-0.25, 0.25 - Math.abs(age - 27) * 0.025);
  const clubBonus = /Madrid|Barcelona|Bayern|Manchester|Liverpool|Arsenal|Chelsea|Paris|Milan|Inter|Juventus|Napoli|Dortmund|PSG/i.test(club) ? 0.28 : 0;
  return round1(Math.min(9.3, base + role + squadOrder + ageCurve + clubBonus));
}

function attrsFor(position, rating, age) {
  const peak = Math.round(rating * 10);
  const paceAge = age > 31 ? -8 : age < 23 ? 5 : 0;
  if (position === "GK") return [45, 35, 68, 55, Math.min(96, peak + 8), Math.min(94, peak + 2)];
  if (position === "DF") return [Math.min(92, peak - 2 + paceAge), 45, Math.min(90, peak - 4), 62, Math.min(96, peak + 8), Math.min(96, peak + 5)];
  if (position === "MF") return [Math.min(92, peak - 2 + paceAge), Math.min(90, peak - 3), Math.min(97, peak + 8), Math.min(95, peak + 4), Math.min(88, peak - 5), Math.min(92, peak)];
  return [Math.min(97, peak + 5 + paceAge), Math.min(96, peak + 8), Math.min(90, peak - 3), Math.min(97, peak + 5), Math.min(70, peak - 25), Math.min(92, peak)];
}

function tagsFor(position) {
  if (position === "GK") return ["门线反应", "出球稳定", "禁区指挥"];
  if (position === "DF") return ["对抗强度", "防线覆盖", "定位球"];
  if (position === "MF") return ["节奏控制", "推进传球", "攻防转换"];
  return ["终结威胁", "跑位冲击", "高压逼抢"];
}

function clean(html) {
  return decode(html.replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim());
}

function normalizePlayerName(name) {
  return String(name)
    .replace(/\s*\((?:C|captain)\)\s*$/i, "")
    .replace(/\s+/g, " ")
    .trim();
}

function decode(value) {
  return String(value)
    .replace(/&amp;/g, "&")
    .replace(/&mdash;/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&#039;/g, "'")
    .replace(/&quot;/g, '"')
    .trim();
}

function numberOrZero(value) {
  const n = Number(String(value).replace(/[^\d.-]/g, ""));
  return Number.isFinite(n) ? n : 0;
}

function slug(value) {
  return value
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
}

function round1(value) {
  return Math.round(value * 10) / 10;
}

function literal(value) {
  return JSON.stringify(value, null, 2);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
